    46→	apiGroupInfo := genericapiserver.NewDefaultAPIGroupInfo(admissionregistration.GroupName, legacyscheme.Scheme, legacyscheme.ParameterCodec, legacyscheme.Codecs)
    47→	// If you add a version here, be sure to add an entry in `k8s.io/kubernetes/cmd/kube-apiserver/app/aggregator.go with specific priorities.
    48→	// TODO refactor the plumbing to provide the information in the APIGroupInfo
    49→
    50→	if storageMap, err := p.v1Storage(apiResourceConfigSource, restOptionsGetter); err != nil {
    51→		return genericapiserver.APIGroupInfo{}, err
    52→	} else if len(storageMap) > 0 {
    53→		apiGroupInfo.VersionedResourcesStorageMap[admissionregistrationv1.SchemeGroupVersion.Version] = storageMap
    54→	}
    55→
    56→	if storageMap, err := p.v1beta1Storage(apiResourceConfigSource, restOptionsGetter); err != nil {
    57→		return genericapiserver.APIGroupInfo{}, err
    58→	} else if len(storageMap) > 0 {
