    99→	// validatingadmissionpolicies
   100→	if resource := "validatingadmissionpolicies"; apiResourceConfigSource.ResourceEnabled(admissionregistrationv1.SchemeGroupVersion.WithResource(resource)) {
   101→		policyStorage, policyStatusStorage, err := validatingadmissionpolicystorage.NewREST(restOptionsGetter, p.Authorizer, r)
   102→		if err != nil {
   103→			return storage, err
   104→		}
   105→		policyGetter = policyStorage
